// worker-public.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    try {
      if (path.startsWith('/api/users')) {
        const response = await env.USER_SERVICE.fetch(request);
        return response;
      } else if (path.startsWith('/api/products')) {
        const response = await env.PRODUCT_SERVICE.fetch(request);
        return response;
      } else if (path.startsWith('/api/orders')) {
        const response = await env.ORDER_SERVICE.fetch(request);
        return response;
      } else if (path.startsWith('/api/analytics')) {
        const response = await env.ANALYTICS_SERVICE.fetch(request);
        return response;
      } else {
        return new Response(JSON.stringify({
          error: 'Not Found',
          message: 'The requested endpoint does not exist',
          availableEndpoints: ['/api/users', '/api/products', '/api/orders', '/api/analytics']
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Internal Server Error',
        message: error.message
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

// worker-user-service.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    if (path === '/api/users' && method === 'GET') {
      const users = await this.getAllUsers(env);
      return new Response(JSON.stringify(users), {
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (path.match(/^\/api\/users\/\d+$/) && method === 'GET') {
      const userId = path.split('/').pop();
      const user = await this.getUserById(userId, env);
      
      if (!user) {
        return new Response(JSON.stringify({ error: 'User not found' }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const analyticsRequest = new Request('http://internal/track', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          event: 'user_viewed',
          userId: userId,
          timestamp: Date.now()
        })
      });
      ctx.waitUntil(env.ANALYTICS_SERVICE.fetch(analyticsRequest));

      return new Response(JSON.stringify(user), {
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (path === '/api/users' && method === 'POST') {
      const userData = await request.json();
      const newUser = await this.createUser(userData, env);
      
      const analyticsRequest = new Request('http://internal/track', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          event: 'user_created',
          userId: newUser.id,
          timestamp: Date.now()
        })
      });
      ctx.waitUntil(env.ANALYTICS_SERVICE.fetch(analyticsRequest));

      return new Response(JSON.stringify(newUser), {
        status: 201,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
      status: 405,
      headers: { 'Content-Type': 'application/json' }
    });
  },

  async getAllUsers(env) {
    return [
      { id: 1, name: 'John Doe', email: 'john@example.com' },
      { id: 2, name: 'Jane Smith', email: 'jane@example.com' }
    ];
  },

  async getUserById(userId, env) {
    const users = await this.getAllUsers(env);
    return users.find(u => u.id === parseInt(userId));
  },

  async createUser(userData, env) {
    return {
      id: Date.now(),
      name: userData.name,
      email: userData.email,
      createdAt: new Date().toISOString()
    };
  }
};

// worker-product-service.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    if (path === '/api/products' && method === 'GET') {
      const products = await this.getAllProducts(env);
      return new Response(JSON.stringify(products), {
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (path.match(/^\/api\/products\/\d+$/) && method === 'GET') {
      const productId = path.split('/').pop();
      const product = await this.getProductById(productId, env);
      
      if (!product) {
        return new Response(JSON.stringify({ error: 'Product not found' }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const analyticsRequest = new Request('http://internal/track', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          event: 'product_viewed',
          productId: productId,
          timestamp: Date.now()
        })
      });
      ctx.waitUntil(env.ANALYTICS_SERVICE.fetch(analyticsRequest));

      return new Response(JSON.stringify(product), {
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (path === '/api/products' && method === 'POST') {
      const productData = await request.json();
      const newProduct = await this.createProduct(productData, env);
      
      return new Response(JSON.stringify(newProduct), {
        status: 201,
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (path === '/api/products/check-stock' && method === 'POST') {
      const { productId, quantity } = await request.json();
      const inStock = await this.checkStock(productId, quantity, env);
      
      return new Response(JSON.stringify({ inStock, productId, quantity }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
      status: 405,
      headers: { 'Content-Type': 'application/json' }
    });
  },

  async getAllProducts(env) {
    return [
      { id: 1, name: 'Laptop', price: 999.99, stock: 50 },
      { id: 2, name: 'Mouse', price: 29.99, stock: 200 },
      { id: 3, name: 'Keyboard', price: 79.99, stock: 150 }
    ];
  },

  async getProductById(productId, env) {
    const products = await this.getAllProducts(env);
    return products.find(p => p.id === parseInt(productId));
  },

  async createProduct(productData, env) {
    return {
      id: Date.now(),
      name: productData.name,
      price: productData.price,
      stock: productData.stock || 0,
      createdAt: new Date().toISOString()
    };
  },

  async checkStock(productId, quantity, env) {
    const product = await this.getProductById(productId, env);
    return product && product.stock >= quantity;
  }
};

// worker-order-service.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    if (path === '/api/orders' && method === 'GET') {
      const orders = await this.getAllOrders(env);
      return new Response(JSON.stringify(orders), {
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (path.match(/^\/api\/orders\/\d+$/) && method === 'GET') {
      const orderId = path.split('/').pop();
      const order = await this.getOrderById(orderId, env);
      
      if (!order) {
        return new Response(JSON.stringify({ error: 'Order not found' }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      return new Response(JSON.stringify(order), {
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (path === '/api/orders' && method === 'POST') {
      const orderData = await request.json();
      
      const userRequest = new Request(`http://internal/api/users/${orderData.userId}`);
      const userResponse = await env.USER_SERVICE.fetch(userRequest);
      
      if (!userResponse.ok) {
        return new Response(JSON.stringify({ error: 'User not found' }), {
          status: 400,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const user = await userResponse.json();

      const stockCheckRequest = new Request('http://internal/api/products/check-stock', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          productId: orderData.productId,
          quantity: orderData.quantity
        })
      });
      const stockResponse = await env.PRODUCT_SERVICE.fetch(stockCheckRequest);
      const stockData = await stockResponse.json();

      if (!stockData.inStock) {
        return new Response(JSON.stringify({ error: 'Product out of stock' }), {
          status: 400,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const newOrder = await this.createOrder(orderData, user, env);

      const analyticsRequest = new Request('http://internal/track', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          event: 'order_created',
          orderId: newOrder.id,
          userId: orderData.userId,
          productId: orderData.productId,
          amount: newOrder.total,
          timestamp: Date.now()
        })
      });
      ctx.waitUntil(env.ANALYTICS_SERVICE.fetch(analyticsRequest));

      return new Response(JSON.stringify(newOrder), {
        status: 201,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
      status: 405,
      headers: { 'Content-Type': 'application/json' }
    });
  },

  async getAllOrders(env) {
    return [
      { id: 1, userId: 1, productId: 1, quantity: 1, total: 999.99, status: 'completed' },
      { id: 2, userId: 2, productId: 2, quantity: 2, total: 59.98, status: 'pending' }
    ];
  },

  async getOrderById(orderId, env) {
    const orders = await this.getAllOrders(env);
    return orders.find(o => o.id === parseInt(orderId));
  },

  async createOrder(orderData, user, env) {
    const productRequest = new Request(`http://internal/api/products/${orderData.productId}`);
    const productResponse = await env.PRODUCT_SERVICE.fetch(productRequest);
    const product = await productResponse.json();

    return {
      id: Date.now(),
      userId: orderData.userId,
      userName: user.name,
      productId: orderData.productId,
      productName: product.name,
      quantity: orderData.quantity,
      total: product.price * orderData.quantity,
      status: 'pending',
      createdAt: new Date().toISOString()
    };
  }
};

// worker-analytics-service.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    if (path === '/track' && method === 'POST') {
      const eventData = await request.json();
      await this.trackEvent(eventData, env);
      
      return new Response(JSON.stringify({ success: true }), {
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (path === '/api/analytics' && method === 'GET') {
      const stats = await this.getAnalytics(env);
      return new Response(JSON.stringify(stats), {
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (path === '/api/analytics/events' && method === 'GET') {
      const events = await this.getRecentEvents(env);
      return new Response(JSON.stringify(events), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
      status: 405,
      headers: { 'Content-Type': 'application/json' }
    });
  },

  async trackEvent(eventData, env) {
    console.log('Event tracked:', eventData);
    return true;
  },

  async getAnalytics(env) {
    return {
      totalEvents: 1523,
      userViews: 456,
      productViews: 789,
      ordersCreated: 123,
      usersCreated: 45,
      lastUpdated: new Date().toISOString()
    };
  },

  async getRecentEvents(env) {
    return [
      { event: 'order_created', orderId: 12345, timestamp: Date.now() - 1000 },
      { event: 'product_viewed', productId: 1, timestamp: Date.now() - 2000 },
      { event: 'user_viewed', userId: 2, timestamp: Date.now() - 3000 }
    ];
  }
};

